# Better approach: only look at lines starting with '>' (the prompt)
# Track the last prompt text across frames
# A command is completed when the prompt text changes to something new
import os, re, glob

files = sorted(glob.glob('/app/ocr/frame_*.txt'))

def get_prompts(text):
    """Get all text after '>' prompt lines (lines starting with '>')."""
    lines = text.strip().split('\n')
    prompts = []
    for line in lines:
        stripped = line.strip()
        if stripped.startswith('>'):
            cmd = stripped[1:].strip()
            prompts.append(cmd)
    return prompts

def get_counter(text):
    m = re.search(r'Moves:\s*(\d+)', text)
    return int(m.group(1)) if m else None

frame_data = []
for f in files:
    text = open(f).read()
    prompts = get_prompts(text)
    counter = get_counter(text)
    frame_data.append({
        'file': os.path.basename(f),
        'prompts': prompts,
        'last': prompts[-1] if prompts else "",
        'counter': counter
    })

# Print first 50 frames
